+/* ============================================================================
+   iOS SAFARI SCROLL FIXES
+   Improves scroll behavior on iOS Safari where nested scroll containers
+   and dynamic viewport can cause janky/broken feeling scroll
+   ============================================================================ */
+
+/* Enable momentum scrolling on iOS for all scrollable containers */
+@supports (-webkit-touch-callout: none) {
+  /* iOS only */
+  [style*="overflow"] {
+    -webkit-overflow-scrolling: touch;
+  }
+
+  .overflow-y-auto,
+  .overflow-y-scroll,
+  .overflow-auto,
+  .overflow-scroll {
+    -webkit-overflow-scrolling: touch;
+  }
+}
+
